// Use reflection on the live Tekla assemblies to fill the v0.30 catalog gaps.
// Truth source: the actual Tekla.Structures.Model.dll loaded into Tekla 2026.

var asm = System.Reflection.Assembly.Load("Tekla.Structures.Model");
var result = new System.Collections.Generic.Dictionary<string, object>();

// --- 4 enums with empty enum_values ---
string[] gapEnums = new[] {
    "Tekla.Structures.Model.Operations.Operation+ExportBasePoint",
    "Tekla.Structures.Model.Operations.Operation+IFC2x3ExportViewTypeEnum",
    "Tekla.Structures.Model.Operations.Operation+IFCExportVersionEnum",
    "Tekla.Structures.Model.Operations.Operation+IFCExportViewTypeEnum"
};
var enumResults = new System.Collections.Generic.Dictionary<string, object>();
foreach (var et in gapEnums) {
    var t = asm.GetType(et);
    if (t == null) { enumResults[et] = "NOT FOUND in assembly"; continue; }
    var values = new System.Collections.Generic.List<object>();
    foreach (var name in System.Enum.GetNames(t)) {
        var val = System.Convert.ToInt32(System.Enum.Parse(t, name));
        values.Add(new { name = name, value = val });
    }
    enumResults[et] = values;
}
result["enums"] = enumResults;

// --- Sample 5 classes-with-no-ctor: check if they actually have public ctors ---
string[] gapClasses = new[] {
    "Tekla.Structures.Model.ClashCheckHandler",
    "Tekla.Structures.Model.ConnectionPart",
    "Tekla.Structures.Catalogs.BoltItemEnumerator",
    "Tekla.Structures.Catalogs.MaterialItemEnumerator",
    "Tekla.Structures.Model.UI.ModelObjectSelector"
};
var classResults = new System.Collections.Generic.Dictionary<string, object>();
foreach (var ct in gapClasses) {
    var t = asm.GetType(ct);
    if (t == null) { classResults[ct] = "NOT FOUND in assembly"; continue; }
    var ctors = t.GetConstructors();
    var ctorSigs = new System.Collections.Generic.List<string>();
    foreach (var c in ctors) {
        var ps = c.GetParameters();
        var paramStr = string.Join(", ", ps.Select(p => p.ParameterType.Name + " " + p.Name));
        ctorSigs.Add($"public {t.Name}({paramStr})");
    }
    classResults[ct] = new {
        is_abstract = t.IsAbstract,
        is_sealed = t.IsSealed,
        ctor_count = ctors.Length,
        ctors = ctorSigs
    };
}
result["classes"] = classResults;

return result;
